// Solo call_analyzed del agente OUTBOUND. Todo lo demás (call_started/ended,
// eventos del agente inbound si compartieran webhook) se descarta en silencio.
const AGENT_OUT = 'agent_042b9fbc990838ae4117315440';
const body = $json.body ?? $json;
if (body.event !== 'call_analyzed') return [];
const call = body.call || {};
if (call.agent_id !== AGENT_OUT) return [];

const an = call.call_analysis || {};
const custom = an.custom_analysis_data || {};
const meta = call.metadata || {};

// Si no hubo conexión real, el resultado lo dicta el disconnect_reason, no el LLM.
const NO_PICKUP = ['dial_no_answer', 'dial_busy', 'dial_failed', 'voicemail_reached', 'machine_detected'];
let resultado = custom.resultado_llamada || 'sin_conversacion';
if (NO_PICKUP.includes(call.disconnect_reason)) resultado = 'no_contesta';

const dur = call.duration_ms != null ? Math.round(call.duration_ms / 1000)
  : (call.end_timestamp && call.start_timestamp ? Math.round((call.end_timestamp - call.start_timestamp) / 1000) : null);

const perfil_zona = (custom.perfil_zona || '').toString().trim();
const _pmin = Number(custom.perfil_precio_min); const _pmax = Number(custom.perfil_precio_max);
const perfil_precio_min = (isFinite(_pmin) && _pmin > 0) ? _pmin : null;
const perfil_precio_max = (isFinite(_pmax) && _pmax > 0) ? _pmax : null;
const perfil_tipo = (custom.perfil_tipo || 'ninguno').toString().trim().toLowerCase();
const perfil_capturado = (custom.perfil_capturado === true || custom.perfil_capturado === 'true');

const perfil_habitaciones = (()=>{const n=parseInt(custom.perfil_habitaciones);return (isFinite(n)&&n>0)?n:null;})();
const perfil_m2 = (()=>{const n=Number(custom.perfil_m2);return (isFinite(n)&&n>0)?n:null;})();
const perfil_banos = (()=>{const n=Number(custom.perfil_banos);return (isFinite(n)&&n>0)?n:null;})();
const perfil_extras = (custom.perfil_extras||'').toString().trim();
const perfil_estado = (custom.perfil_estado||'').toString().trim();

return [{ json: {
  call_id: call.call_id,
  lead_id: meta.lead_id ?? null,
  attempt: meta.attempt ?? null,
  resultado,
  motivo_no_interes: custom.motivo_no_interes || 'no_aplica',
  nuevo_contacto_preferido: custom.nuevo_contacto_preferido || 'ninguno',
  disconnect_reason: call.disconnect_reason || '',
  duration_s: dur,
  call_summary: an.call_summary || '',
  perfil_capturado, perfil_zona, perfil_precio_min, perfil_precio_max, perfil_tipo,
  perfil_habitaciones, perfil_m2, perfil_banos, perfil_extras, perfil_estado,
}}];

// Decide qué hacer en Kommo según el resultado. El RPC ya garantizó idempotencia
// (si este nodo corre, es la PRIMERA vez que se procesa este call_id).
//
// NOTA visita_agendada: NO movemos el lead original a Lead Caliente a propósito —
// la tool Reservar del flow ya dispara el circuito estándar de confirmación
// (lead en Lead Caliente + salesbot 87865); mover también este lead duplicaría
// la plantilla de confirmación con el CF "Día de visita" vacío.
const ev = $('Filtrar evento').first().json;
const ENUM = { visita_agendada: 1027074, no_interesado: 1027076, pide_mas_info: 1027078,
               derivado_humano: 1027080, sin_conversacion: 1027082, no_contesta: 1027084 };
const RAMON = 15113339;
const r = ev.resultado;
const leadId = Number(ev.lead_id);
if (!leadId) return []; // sin lead_id en metadata no podemos actualizar Kommo

const patch = { id: leadId, custom_fields_values: [
  { field_id: 1376610, values: [{ enum_id: ENUM[r] || ENUM.sin_conversacion }] },
]};

const MOTIVO = { ya_compro: 'ya compró', cambio_zona: 'cambió de zona', presupuesto: 'presupuesto',
                 momento_incorrecto: 'mal momento', otro: 'otro motivo' };
let nota = `Llamada IA de reactivación (intento ${ev.attempt ?? '?'}) — resultado: ${r.replace(/_/g, ' ')}.`;
let task = null;

if (r === 'no_interesado') {
  patch.status_id = 143; // Venta Perdido
  nota += ` Motivo: ${MOTIVO[ev.motivo_no_interes] || 'no indicado'}. Lead cerrado automáticamente.`;
} else if (r === 'visita_agendada') {
  nota += ' La visita se gestionó por el circuito estándar de reserva (confirmación WA enviada).';
} else if (r === 'derivado_humano') {
  nota += ' El cliente pidió hablar con una persona — se le prometió que le llamamos.';
  task = { text: `LLAMAR HOY: ${ev.call_summary ? ev.call_summary.slice(0, 200) : 'cliente pidió hablar con una persona en llamada IA de reactivación'}`,
           hours: 4 };
} else if (r === 'pide_mas_info') {
  nota += ' Sigue interesado pero no agendó.';
  if (ev.nuevo_contacto_preferido && ev.nuevo_contacto_preferido !== 'ninguno')
    nota += ` Prefiere contacto por: ${ev.nuevo_contacto_preferido.replace(/_/g, ' ')}.`;
  task = { text: `Seguimiento: lead pidió más info en llamada IA de reactivación. ${ev.call_summary ? ev.call_summary.slice(0, 200) : ''}`.trim(),
           hours: 24 };
}
if (ev.nuevo_contacto_preferido === 'no_contactar') {
  nota += ' ⚠ Pidió NO ser contactado: desmarcar consentimiento outbound.';
  patch.custom_fields_values.push({ field_id: 1376604, values: [{ value: false }] });
}
if (ev.call_summary && r !== 'no_contesta') nota += `\n\nResumen: ${ev.call_summary}`;
if (ev.duration_s != null) nota += `\nDuración: ${ev.duration_s}s.`;


// ---- Persistencia de perfil de búsqueda (post-call, sin latencia en llamada) ----
let _lead = {};
try { let d = $('Get lead actual').first().json; d = (d && d.data!==undefined) ? d.data : d; if (typeof d === 'string') d = JSON.parse(d); _lead = (d && d._embedded && Array.isArray(d._embedded.leads) && d._embedded.leads[0]) ? d._embedded.leads[0] : (d || {}); } catch(e) { _lead = {}; }
const curStatus = Number(_lead.status_id) || null;
const curPipe = Number(_lead.pipeline_id) || null;
const POOL = new Set([106971083,105358051,105358071]);
const PIPE_POOL = {13546071:106971083, 13652231:105358051, 13652235:105358071};
const TIPO_ENUM = {piso:1025940, atico:1025942, duplex:1025944, chalet:1025946, 'local-oficina':1025948};

// enums perfil avanzado
const HAB_ENUM={1:1019827,2:1019829,3:1019831,4:1019833};
function habEnum(n){n=parseInt(n)||0;if(n<=0)return null;if(n>=5)return 1019835;return HAB_ENUM[n]||null;}
const EXTRA_ENUM={piscina:1025950,terraza:1025952,jardin:1025954,trastero:1025956,garaje:1025958,ascensor:1025960,exterior:1025962,'aire acondicionado':1025964,aire:1025964};
const ESTADO_ENUM={'entrar a vivir':1025966,'a reformar':1025968,reformar:1025968,'obra nueva':1025970,'obra':1025970};
const _normp=s=>(s||'').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim();
function mapMulti(str,dict){if(!str)return [];return [...new Set(str.split(/[,;]+/).map(x=>dict[_normp(x)]).filter(Boolean))].map(id=>({enum_id:id}));}
let trigger_reconcile = false;
const persistOk = ev.perfil_capturado === true && !['no_interesado','derivado_humano','visita_agendada'].includes(r);
if (persistOk) {
  if (ev.perfil_zona) patch.custom_fields_values.push({ field_id: 1373285, values: [{ value: ev.perfil_zona }] });
  if (ev.perfil_precio_min) patch.custom_fields_values.push({ field_id: 1376044, values: [{ value: ev.perfil_precio_min }] });
  if (ev.perfil_precio_max) patch.custom_fields_values.push({ field_id: 1376040, values: [{ value: ev.perfil_precio_max }] });
  if (ev.perfil_tipo && TIPO_ENUM[ev.perfil_tipo]) patch.custom_fields_values.push({ field_id: 1376076, values: [{ enum_id: TIPO_ENUM[ev.perfil_tipo] }] });
  if (ev.perfil_habitaciones && habEnum(ev.perfil_habitaciones)) patch.custom_fields_values.push({ field_id: 1373289, values: [{ enum_id: habEnum(ev.perfil_habitaciones) }] });
  if (ev.perfil_m2) patch.custom_fields_values.push({ field_id: 1373287, values: [{ value: ev.perfil_m2 }] });
  if (ev.perfil_banos) patch.custom_fields_values.push({ field_id: 1376078, values: [{ value: ev.perfil_banos }] });
  const _ex=mapMulti(ev.perfil_extras,EXTRA_ENUM); if(_ex.length) patch.custom_fields_values.push({ field_id: 1376080, values: _ex });
  const _es=mapMulti(ev.perfil_estado,ESTADO_ENUM); if(_es.length) patch.custom_fields_values.push({ field_id: 1376082, values: _es });
  const hayCriterio = !!(ev.perfil_zona || ev.perfil_precio_min || ev.perfil_precio_max || (ev.perfil_tipo && TIPO_ENUM[ev.perfil_tipo]) || ev.perfil_habitaciones || ev.perfil_m2 || ev.perfil_banos || mapMulti(ev.perfil_extras,EXTRA_ENUM).length || mapMulti(ev.perfil_estado,ESTADO_ENUM).length);
  if (hayCriterio) {
    // Mover a 'Buscando vivienda' del pipeline del lead, solo si aún no está en un pool.
    if (curStatus && !POOL.has(curStatus)) { const target = PIPE_POOL[curPipe]; if (target) patch.status_id = target; }
    trigger_reconcile = true;
    const _resumen = [ev.perfil_zona, (ev.perfil_precio_min||ev.perfil_precio_max)?('precio '+(ev.perfil_precio_min||'?')+'-'+(ev.perfil_precio_max||'?')):'', (ev.perfil_tipo&&ev.perfil_tipo!=='ninguno')?ev.perfil_tipo:''].filter(Boolean).join(', ');
    nota += ' Perfil de búsqueda capturado y guardado (' + _resumen + '). Lead disponible para matching.';
  }
}

return [{ json: {
  call_id: ev.call_id, lead_id: leadId,
  patch_body: [patch],
  nota_body: [{ note_type: 'common', params: { text: nota } }],
  trigger_reconcile,
  task_body: task ? [{ task_type_id: 1, text: task.text,
    complete_till: Math.floor(Date.now() / 1000) + task.hours * 3600,
    entity_id: leadId, entity_type: 'leads', responsible_user_id: RAMON }] : null,
}}];
